    s1=set(F1[r1-1])
    s2=set(F2[r2-1])
    sx=s1.intersection(s2)
    if len(sx)>1:
        return "Bad magician!"
    elif len(sx)==0:
        return "Volunteer cheated!"
    else:
        return sx.__iter__().next()



