def click(C, F, X):
    states = Queue.PriorityQueue()

    states.put((0.0, 2.0, False))
    while not states.empty():
        time, rate, is_done = states.get()

        if is_done:
            return time

        states.put((
            time + X / rate,
            rate,
            True
        ))

        states.put((
            time + C / rate,
            rate + F,
            False
        ))

    return None

